const data = $input.first().json;
const jobs = data.jobs || [];
const kw = /web|javascript|react|vue|angular|node|python|ai|ia|automation|automatisation|fullstack|frontend|backend|wordpress|php|n8n|langchain|chatbot|llm/i;
return jobs.filter(j => kw.test(`${j.title||''} ${j.description||''} ${(j.tags||[]).join(' ')}`)).slice(0,10).map(j => ({ json: { id:`remotive_${j.id}`, title:j.title||'Sans titre', company:j.company_name||'Inconnu', description:(j.description||'').replace(/<[^>]*>/g,'').substring(0,600), url:j.url||'', platform:'Remotive', skills:(j.tags||[]).join(', '), posted_at:j.publication_date||new Date().toISOString() } }));

const xml = $input.first().json?.data || String($input.first().json);
const items=[];
const re=/<item>([\s\S]*?)<\/item>/g;
let m;
while((m=re.exec(xml))!==null){
  const it=m[1];
  const get=tag=>{for(const p of[new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/${tag}>`),new RegExp(`<${tag}[^>]*>([^<]*)<\/${tag}>`)]) {const r=it.match(p);if(r)return r[1].trim();}return '';};
  const title=get('title'),link=get('link')||get('guid'),desc=get('description');
  if(title){const slug=link.split('/').filter(Boolean).pop()||Math.random().toString(36).substr(2,9);items.push({json:{id:`wwr_${slug}`,title:title.includes(':')?title.split(':').slice(1).join(':').trim():title,company:title.includes(':')?title.split(':')[0].trim():'WWR',description:desc.replace(/<[^>]*>/g,'').substring(0,600),url:link,platform:'WeWorkRemotely',skills:'',posted_at:new Date().toISOString()}});}
}
const kw=/web|javascript|react|vue|angular|node|python|ai|ia|automation|fullstack|frontend|backend|wordpress|php/i;
return items.filter(i=>kw.test(`${i.json.title} ${i.json.description}`)).slice(0,10);

const xml = $input.first().json?.data || String($input.first().json);
const items=[];
const re=/<item>([\s\S]*?)<\/item>/g;
let m;
while((m=re.exec(xml))!==null){
  const it=m[1];
  const get=tag=>{for(const p of[new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/${tag}>`),new RegExp(`<${tag}[^>]*>([^<]*)<\/${tag}>`)]) {const r=it.match(p);if(r)return r[1].trim();}return '';};
  const title=get('title'),link=get('link')||get('guid'),desc=get('description'),source=get('source')||'Indeed';
  if(title){const slug=link.split('jk=')[1]?.substring(0,16)||Math.random().toString(36).substr(2,9);items.push({json:{id:`indeed_${slug}`,title,company:source,description:desc.replace(/<[^>]*>/g,'').substring(0,600),url:link,platform:'Indeed France',skills:'',posted_at:new Date().toISOString()}});}
}
const kw=/web|javascript|react|vue|angular|node|python|ai|ia|automation|automatisation|fullstack|frontend|backend|wordpress|php|freelance/i;
return items.filter(i=>kw.test(`${i.json.title} ${i.json.description}`)).slice(0,10);

const data = $input.first().json;
const jobs = data.data || [];

return jobs.slice(0, 10).map(j => ({
  json: {
    id: `jsearch_${j.job_id || Math.random().toString(36).substr(2,9)}`,
    title: j.job_title || 'Sans titre',
    company: j.employer_name || 'Inconnu',
    description: (j.job_description || '').substring(0, 600),
    url: j.job_apply_link || j.job_google_link || '',
    platform: `JSearch/${j.job_publisher || 'LinkedIn'}`,
    skills: (j.job_required_skills || []).join(', '),
    posted_at: j.job_posted_at_datetime_utc || new Date().toISOString()
  }
}));

const data = $input.first().json;
const projects = data?.result?.projects || [];

return projects.slice(0, 10).map(p => ({
  json: {
    id: `freelancer_${p.id}`,
    title: p.title || 'Sans titre',
    company: `Client #${p.owner_id || '?'}`,
    description: (p.description || '').substring(0, 600),
    url: `https://www.freelancer.com/projects/${p.seo_url || p.id}`,
    platform: 'Freelancer.com',
    skills: (p.jobs || []).map(j => j.name).join(', '),
    budget: p.budget ? `${p.budget.minimum}-${p.budget.maximum} ${p.currency?.sign || '$'}` : 'N/A',
    posted_at: p.time_submitted ? new Date(p.time_submitted * 1000).toISOString() : new Date().toISOString()
  }
}));

const staticData = $getWorkflowStaticData('global');
if (!staticData.appliedJobs) staticData.appliedJobs = [];

const allJobs = $input.all().map(item => item.json).filter(j => j && j.id);

const seenIds = new Set();
const newJobs = allJobs.filter(job => {
  if (staticData.appliedJobs.includes(job.id)) return false;
  if (seenIds.has(job.id)) return false;
  seenIds.add(job.id);
  return true;
});

const toProcess = newJobs.slice(0, 3);
console.log(`Total: ${allJobs.length} | Nouvelles: ${newJobs.length} | A traiter: ${toProcess.length}`);

if (toProcess.length === 0) {
  return [{ json: { __noJobs: true, message: 'Aucune nouvelle offre' } }];
}
return toProcess.map(job => ({ json: job }));

