Rédige UNIQUEMENT le message, sans intro ni commentaire.`;

return [{ json: { ...job, claudePrompt: prompt } }];

const claudeResponse = $input.item.json;
const jobData = $('Préparer Prompt').item.json;
const coverLetter = claudeResponse.content?.[0]?.text || 'Erreur génération message';
return [{ json: { jobId:jobData.id, jobTitle:jobData.title, jobCompany:jobData.company, jobPlatform:jobData.platform, jobUrl:jobData.url, jobSkills:jobData.skills, jobBudget:jobData.budget||'N/A', coverLetter, emailSubject:`Candidature Freelance - ${jobData.title} | Tony PAYET`, generatedAt:new Date().toISOString() } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.appliedJobs) staticData.appliedJobs = [];
const jobId = $input.item.json.jobId;
if (jobId && !staticData.appliedJobs.includes(jobId)) {
  staticData.appliedJobs.push(jobId);
  if (staticData.appliedJobs.length > 2000) staticData.appliedJobs = staticData.appliedJobs.slice(-2000);
}
console.log(`Email envoye: ${$input.item.json.jobTitle} @ ${$input.item.json.jobCompany}`);
console.log(`Total traites: ${staticData.appliedJobs.length}`);
return $input.all();
